/**
 * End-to-end stats: point byte-snap at a real build step and measure what it saves.
 *
 *   node e2e.js
 *
 * The build step under measurement is the `compress-shader-literals` plugin. We run
 * its transform over the JS actually shipped by each benchmarked package, then use
 * byte-snap's own `snap` + `diff` engine to measure the byte delta — dogfooding the
 * tool as a size meter. Results are printed and injected into the repo README between
 * the <!-- STATS:START --> / <!-- STATS:END --> markers.
 *
 * Benchmark targets are autogenerated from package.json `dependencies`; the plugin
 * itself (`compress-shader-literals`) is excluded automatically.
 */
import { existsSync, readFileSync, readdirSync, statSync, writeFileSync } from 'node:fs';
import { dirname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

import { diff, snap } from '../src/index.js';

const here = dirname(fileURLToPath(import.meta.url));

const TOOL = 'compress-shader-literals';
const README = resolve(here, '..', 'README.md');

const deps = Object.keys(JSON.parse(readFileSync(resolve(here, 'package.json'), 'utf8')).dependencies ?? {});
const targets = deps.filter((name) => name !== TOOL);

// Grab the plugin's raw transform once. unplugin exposes hooks as fn or { handler }.
const { compressShaderLiterals } = await import(TOOL);
// exclude: [] — targets live under node_modules, which the plugin skips by default.
const raw = compressShaderLiterals.raw({ exclude: [] }, { framework: 'rollup' });
const transform = typeof raw.transform === 'function' ? raw.transform : raw.transform.handler;
const ctx = { error() {}, warn() {} }; // minimal rollup plugin context

function pkgDir(name) {
  // Resolve the package's entry, then walk the dir it ships from. Use
  // import.meta.resolve so import-only `exports` maps (no `require`) still resolve.
  return dirname(fileURLToPath(import.meta.resolve(name)));
}

function jsFiles(dir, out = []) {
  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    const full = join(dir, entry.name);
    if (entry.isDirectory()) {
      if (entry.name !== 'node_modules') jsFiles(full, out);
    } else if (/\.[mc]?js$/.test(entry.name) && statSync(full).size > 0) {
      out.push(full);
    }
  }
  return out;
}

async function measure(name) {
  const dir = pkgDir(name);
  let beforeText = '';
  let afterText = '';
  let touched = 0;

  for (const file of jsFiles(dir)) {
    const code = readFileSync(file, 'utf8');
    const result = await transform.call(ctx, code, file);
    const out = result && (result.code ?? result);
    if (out && out !== code) {
      beforeText += code;
      afterText += out;
      touched++;
    }
  }

  const report = diff(snap.text(beforeText), snap.text(afterText));
  return { name, files: touched, ...report.json() };
}

function pct(n) {
  return `${n.toFixed(1)}%`;
}

function table(rows) {
  const total = rows.reduce(
    (a, r) => ({
      files: a.files + r.files,
      beforeBytes: a.beforeBytes + r.beforeBytes,
      afterBytes: a.afterBytes + r.afterBytes,
    }),
    { files: 0, beforeBytes: 0, afterBytes: 0 }
  );
  const totalSaved = total.beforeBytes - total.afterBytes;
  const totalPct = total.beforeBytes ? (totalSaved / total.beforeBytes) * 100 : 0;

  const line = (name, files, before, after, p) =>
    `| ${name} | ${files} | ${before.toLocaleString()} B | ${after.toLocaleString()} B | **${pct(p)}** |`;

  return [
    '| Package | Files | Before | After | Saved |',
    '| --- | ---: | ---: | ---: | ---: |',
    ...rows.map((r) => line(`\`${r.name}\``, r.files, r.beforeBytes, r.afterBytes, r.savedPercent)),
    line('**Total**', total.files, total.beforeBytes, total.afterBytes, totalPct),
    '',
    `_Measured by byte-snap across ${rows.length} package(s), running the \`${TOOL}\` build step._`,
  ].join('\n');
}

function injectReadme(md) {
  if (!existsSync(README)) return;
  const block = `<!-- STATS:START -->\n\n${md}\n\n<!-- STATS:END -->`;
  const re = /<!-- STATS:START -->[\s\S]*?<!-- STATS:END -->/;
  const readme = readFileSync(README, 'utf8');
  if (re.test(readme)) writeFileSync(README, readme.replace(re, block));
}

const rows = [];
for (const name of targets) {
  try {
    rows.push(await measure(name));
  } catch (err) {
    console.error(`✗ ${name} — ${err.message.split('\n')[0]}`);
  }
}

const md = table(rows);
console.log(`\nbyte-snap × ${TOOL}\n`);
console.log(md + '\n');
injectReadme(md);

// One hard assertion so this fails CI if measurement silently breaks.
const ok = rows.length > 0 && rows.some((r) => r.savedBytes > 0);
if (!ok) {
  console.error('No measurable savings recorded — measurement is broken.');
  process.exit(1);
}
